    ('cat_learning_tower_step_stool', 4, 4, 'visible', true, true, 'Best for bathroom step stool', 'BabyBjorn Step Stool', 'BabyBjÃ¶rn', 'Boots', 'https://www.boots.com/babybjorn-step-stool-white-10220346', NULL, 'Â£34.99', 'in_stock', 'Ages 1-5', 'A sturdy step stool for reaching the sink to wash hands and brush teeth, with a non slip standing surface for little feet.', 'Not every home needs a full tower; a safe step stool covers sink jobs. Handwashing and toothbrushing become theirs with a small height boost. Best when kitchen help is already sorted and bathroom independence is the next ask. Stay nearby while they try BabyBjorn Step Stool, then stop on a good note.', 'Not every home needs a full tower; a safe step stool covers sink jobs. Handwashing and toothbrushing become theirs with a small height boost. Best when kitchen help is already sorted and bathroom independence is the next ask. Stay nearby while they try BabyBjorn Step Stool, then stop on a good note.', NULL, 'buy', false, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_learning_tower_step_stool', 5, 5, 'visible', true, true, 'Best for small child stool seat', 'IKEA FORSIKTIG Children''s Stool', 'IKEA', 'IKEA UK', 'https://www.ikea.com/gb/en/p/forsiktig-children-s-stool-white-green-60248418/', NULL, '£10.00', 'in_stock', 'Ages 1-5', 'A small children''s stool they can drag to the sink or hob helper spot, with a friendly height for nearly two.', 'Near two, a stool they can drag to the sink often beats a big tower in a tiny kitchen. FORSIKTIG is the second IKEA option when TROGEN is out. Keep supervision close at the counter. Put IKEA FORSIKTIG Children''s Stool where you both sit most evenings so the invite is easy.', 'Near two, a stool they can drag to the sink often beats a big tower in a tiny kitchen. FORSIKTIG is the second IKEA option when TROGEN is out. Keep supervision close at the counter. Put IKEA FORSIKTIG Children''s Stool where you both sit most evenings so the invite is easy.', NULL, 'buy', true, NULL, NULL, 'Supervise climbs.', 'good', ARRAY[]::text[], 'none'),
    ('cat_picture_story_books', 1, 1, 'visible', true, false, 'Best for chant along story', 'We''re Going on a Bear Hunt (board book)', 'Walker Books', 'Penguin UK', 'https://www.penguin.co.uk/books/108950/were-going-on-a-bear-hunt-by-rosen-michael/9781406363074', NULL, 'Â£7.99', 'in_stock', 'Ages 1-5', 'A sturdy board book of the classic chant along bear hunt, with swishy splashy sounds to join in on every page.', 'Words are joining up into little stories with repeats they can shout. Bear Hunt hands them the chorus. Borrow first if grandparents already own it, then buy a board copy if it becomes the nightly ask. Keep We''re Going on a in easy reach for the next short try.', 'Words are joining up into little stories with repeats they can shout. Bear Hunt hands them the chorus. Borrow first if grandparents already own it, then buy a board copy if it becomes the nightly ask. Keep We''re Going on a in easy reach for the next short try.', NULL, 'borrow', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_picture_story_books', 2, 2, 'visible', true, true, 'Best for lift the flap classic', 'Dear Zoo (board book)', 'Campbell Books', 'Penguin UK', 'https://www.penguin.co.uk/books/451946/dear-zoo-by-campbell-rod/9780230743076', NULL, 'Â£6.99', 'in_stock', 'Ages 1-5', 'A board book with flaps to lift as each animal arrives from the zoo, ending with the perfect pet surprise.', 'Lifting flaps keeps little stories active when attention is short. Dear Zoo is the UK default for that game. Check the shelf before gifting; many homes already have a battered copy. Leave Dear Zoo out where they can find it again tomorrow.', 'Lifting flaps keeps little stories active when attention is short. Dear Zoo is the UK default for that game. Check the shelf before gifting; many homes already have a battered copy. Leave Dear Zoo out where they can find it again tomorrow.', NULL, 'borrow', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_picture_story_books', 3, 3, 'visible', true, true, 'Best for press the page play', 'Press Here', 'Chronicle Books', 'Hachette UK', 'https://www.hachette.co.uk/titles/herve-tullet/press-here/9780811879545/', NULL, 'Â£8.99', 'in_stock', 'Ages 1-5', 'A picture book that asks your child to press, rub and tip the page so dots move, grow and party across the spreads.', 'Interactive pages turn listening into doing. Press Here invites taps and tips without batteries. Lovely when they already enjoy flaps and want a different kind of page job. One short go with Press Here is enough before you tidy away.', 'Interactive pages turn listening into doing. Press Here invites taps and tips without batteries. Lovely when they already enjoy flaps and want a different kind of page job. One short go with Press Here is enough before you tidy away.', NULL, 'borrow', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_picture_story_books', 4, 4, 'visible', true, true, 'Best for rhyming frog fun', 'Oi Frog!', 'Hodder', 'Hachette UK', 'https://www.hachette.co.uk/titles/kes-gray/oi-frog/9781444910865/', NULL, 'Â£7.99', 'in_stock', 'Ages 2+', 'A bright rhyming picture book about where frogs sit, packed with silly animals and sounds to shout on each page.', 'Rhyme and shout backs help words join up. Oi Frog is pure silliness with a clear pattern. Good when Bear Hunt is already worn and you want a louder sofa story. Stay nearby while they try Oi Frog!, then stop on a good note.', 'Rhyme and shout backs help words join up. Oi Frog is pure silliness with a clear pattern. Good when Bear Hunt is already worn and you want a louder sofa story. Stay nearby while they try Oi Frog!, then stop on a good note.', NULL, 'borrow', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_picture_story_books', 5, 5, 'visible', true, true, 'Best for tickle repeat read', 'The Tickle Book', 'Macmillan', 'Hachette UK', 'https://www.hachette.co.uk/titles/ian-whybrow/the-tickle-book/9780230747098/', NULL, 'Â£7.99', 'in_stock', 'Ages 1-5', 'A playful picture book full of tickles, giggles and animals to find, built for repeating the joke together. for sharing on the sofa at home.', 'Giggle stories keep nearly two attention on the page. Tickle Book is light and physical without needing flaps. Nice when you want a short sunny read before bed. Put The Tickle Book where you both sit most evenings so the invite is easy.', 'Giggle stories keep nearly two attention on the page. Tickle Book is light and physical without needing flaps. Nice when you want a short sunny read before bed. Put The Tickle Book where you both sit most evenings so the invite is easy.', NULL, 'borrow', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_picture_story_books', 6, 6, 'visible', true, true, 'Best for hungry caterpillar staple', 'The Very Hungry Caterpillar', 'Puffin', 'Penguin UK', 'https://www.penguin.co.uk/books/57093/the-very-hungry-caterpillar-by-carle-eric/9780241003008', NULL, 'Â£7.99', 'in_stock', 'Ages 1-5', 'The classic holey board book story of a caterpillar eating through the week before becoming a butterfly. for sharing on the sofa at home.', 'Counting days and foods turns into a tiny story arc. Most UK shelves already have it, so borrow or bring back out first. Still earns a Top 10 place for how clearly the week story lands for nearly two. Put The Very Hungry Caterpillar where you both sit most evenings so the invite is easy.', 'Counting days and foods turns into a tiny story arc. Most UK shelves already have it, so borrow or bring back out first. Still earns a Top 10 place for how clearly the week story lands for nearly two. Put The Very Hungry Caterpillar where you both sit most evenings so the invite is easy.', NULL, 'bring_back_out', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_picture_story_books', 7, 7, 'visible', true, true, 'Best for colour repeat read', 'Brown Bear, Brown Bear, What Do You See?', 'Puffin', 'Penguin UK', 'https://www.penguin.co.uk/books/108950/brown-bear-brown-bear-what-do-you-see-by-martin-bill/9780805047905', NULL, 'Â£7.99', 'in_stock', 'Ages 1-5', 'A rhythmic colour and animal book that asks what each creature sees next, inviting your child to predict the page.', 'Prediction is a new story skill as words join up. Brown Bear hands them the pattern. Check stock; some editions sell out, and many nurseries already know it cold. Let them finish the turn with Brown Bear, Brown Bear,, then close the activity kindly.', 'Prediction is a new story skill as words join up. Brown Bear hands them the pattern. Check stock; some editions sell out, and many nurseries already know it cold. Let them finish the turn with Brown Bear, Brown Bear,, then close the activity kindly.', NULL, 'borrow', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'check_stock'),
    ('cat_picture_story_books', 8, 8, 'visible', true, true, 'Best for cheeky pigeon board book', 'Don''t Let the Pigeon Drive the Bus! (board)', 'Walker Books', 'Hachette UK', 'https://www.hachette.co.uk/titles/mo-willems/don-t-let-the-pigeon-drive-the-bus/9781406386073/', NULL, 'Â£6.99', 'in_stock', 'Ages 1-5', 'A sturdy board book where the cheeky pigeon keeps asking to drive the bus, and your child gets to say no on every spread.', 'Saying a firm funny no is useful once opinions arrive. The pigeon argues back and they hold the line. Second Walker title after Bear Hunt; still distinct on answering back. If interest fades, pack Don''t Let the Pigeon away and try again another day.', 'Saying a firm funny no is useful once opinions arrive. The pigeon argues back and they hold the line. Second Walker title after Bear Hunt; still distinct on answering back. If interest fades, pack Don''t Let the Pigeon away and try again another day.', NULL, 'borrow', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_picture_story_books', 9, 9, 'visible', true, true, 'Best for shark peek story', 'Shark in the Park', 'Random House', 'Hachette UK', 'https://www.hachette.co.uk/titles/nick-sharratt/shark-in-the-park/9780552549776/', NULL, 'Â£7.99', 'in_stock', 'Ages 1-5', 'A telescopic peek through picture book about spotting a shark in the park, with jokes that grow on each reread.', 'Peek stories reward looking again. Shark in the Park is a UK sofa favourite for that. Good when flaps feel babyish and you want a proper little story joke. Use Shark in the Park as the second option when the first favourite is already out.', 'Peek stories reward looking again. Shark in the Park is a UK sofa favourite for that. Good when flaps feel babyish and you want a proper little story joke. Use Shark in the Park as the second option when the first favourite is already out.', NULL, 'borrow', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_picture_story_books', 10, 10, 'visible', true, true, 'Best for hug story for bedtime', 'Hugless Douglas', 'Hodder', 'Hachette UK', 'https://www.hachette.co.uk/titles/david-melling/hugless-douglas/9780340999080/', NULL, 'Â£7.99', 'in_stock', 'Ages 1-5', 'A warm bedtime hug story about a bear searching for the right hug, with soft humour and a gentle ending for sofa reads.', 'Hug stories fit the end of a busy day when words are joining up into feelings too. Douglas keeps looking until he finds his person. Check stock; some listings go thin, and many homes already have a copy. Keep the session short with Hugless Douglas so it stays a friendly invite.', 'Hug stories fit the end of a busy day when words are joining up into feelings too. Douglas keeps looking until he finds his person. Check stock; some listings go thin, and many homes already have a copy. Keep the session short with Hugless Douglas so it stays a friendly invite.', NULL, 'borrow', true, NULL, 'High duplication risk â€” check the shelf and library first.', NULL, 'strong', ARRAY[]::text[], 'check_stock'),
    ('cat_play_kitchen_household_props', 1, 1, 'visible', true, false, 'Best for first chopping set', 'ELC Wooden Fruit Chopping Board', 'Early Learning Centre', 'Smyths Toys', 'https://www.smythstoys.com/uk/en-gb/toys/preschool-toys/role-play-and-dress-up/play-kitchens-and-shops/elc-wooden-fruit-chopping-board/p/189194', NULL, 'Â£12.99', 'in_stock', 'Suitable from 18 months', 'A wooden chopping board with chunky velcro fruit pieces and a play knife, so children who are nearly two can slice, name and serve pretend fruit salad on the kitchen floor.', 'Pretend play is getting richer around nearly two: chopping, naming and serving, not only stirring a plastic pan. This set keeps the job small and clear, with fruit pieces that stay together until they cut. A gentle first kitchen prop when a full play kitchen still feels huge.', 'Chop-and-serve pretend matches richer household play.', NULL, 'buy', true, NULL, NULL, NULL, 'good', ARRAY[]::text[], 'none'),
    ('cat_play_kitchen_household_props', 2, 2, 'visible', true, true, 'Best for savoury chopping twin', 'ELC Wooden Vegetable Chopping Board', 'Early Learning Centre', 'Smyths Toys', 'https://www.smythstoys.com/uk/en-gb/toys/preschool-toys/role-play-and-dress-up/play-kitchens-and-shops/elc-wooden-vegetable-chopping-board/p/189195', NULL, 'Â£12.99', 'in_stock', 'Suitable from 18 months', 'A matching wooden board with velcro vegetables and a play knife, for chopping carrots and tomatoes beside the fruit set during pretend tea.', 'Once fruit chopping is familiar, vegetables stretch the same kitchen story into dinner and soup. The board stays the same job, so the shift is words and menus, not a new skill. Handy when they already love the fruit board and want a second crate of names.', 'Extends food naming in kitchen pretend.', NULL, 'buy', true, NULL, NULL, NULL, 'good', ARRAY[]::text[], 'none'),
    ('cat_play_kitchen_household_props', 3, 3, 'visible', true, true, 'Best for breakfast toaster set', 'Bigjigs Wooden Breakfast Set', 'Bigjigs Toys', 'Smyths', 'https://www.smythstoys.com/uk/en-gb/toys/preschool-toys/role-play-and-dress-up/play-kitchens-and-shops/bigjigs-toys-breakfast-set/p/189291', NULL, 'Â£24.99', 'in_stock', 'Suitable for children from 18 Months +', 'A wooden toaster with toast slices, butter dish and jam pot, so children who are nearly two can make pretend breakfast and slide toast up and down.', 'Morning routines become stories at nearly two: toast pops, butter spreads, jam goes on. This set turns that everyday sequence into play they can lead. Strong when they already copy breakfast jobs and want their own toaster right beside yours.', 'Daily breakfast sequence pretend.', NULL, 'buy', true, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'check_url'),
    ('cat_play_kitchen_household_props', 4, 4, 'visible', true, true, 'Best for savoury food crate', 'Bigjigs Butchers Crate', 'Bigjigs Toys', 'Smyths', 'https://www.smythstoys.com/uk/en-gb/toys/preschool-toys/role-play-and-dress-up/play-kitchens-and-shops/bigjigs-toys-butchers-crate/p/160294', NULL, 'Â£15.99', 'in_stock', 'Suitable for children from 18 Months +', 'A wooden crate of play meats such as bacon, steak and sausage pieces, ready to cook on a pretend hob or pack into a shopping bag.', 'Shopping and cooking stories need more than fruit once pretend kitchens get busy. This crate adds savoury pieces they can name, tip and serve. Useful when chopping sets are already loved and the missing piece is something to fry or grill.', 'Savoury food props for kitchen stories.', NULL, 'buy', true, NULL, NULL, NULL, 'good', ARRAY[]::text[], 'check_url'),
    ('cat_play_kitchen_household_props', 5, 5, 'visible', true, true, 'Best for food group sorting play', 'Melissa & Doug Food Groups Play Set', 'Melissa & Doug', 'Smyths Toys', 'https://www.smythstoys.com/uk/en-gb/toys/preschool-toys/role-play-and-dress-up/play-kitchens-and-shops/melissa-doug-food-groups/p/193000', NULL, 'Â£29.99', 'in_stock', 'Ages 2+', 'A wooden play food set sorted into familiar food groups, with pieces for filling plates, baskets and pretend shopping bags during kitchen play.', 'Near two, dinner starts sorting into piles: fruit here, bread there, something for teddy. Named food groups give more plate variety without buying a full kitchen unit. Put Melissa & Doug Food where you both sit most evenings so the invite is easy.', 'Named food variety for richer pretend meals.', NULL, 'buy', true, NULL, NULL, NULL, 'good', ARRAY[]::text[], 'check_url'),
    ('cat_potty_chair', 1, 1, 'visible', true, false, 'Best for classic potty chair', 'BabyBjorn Potty Chair', 'BabyBjÃ¶rn', 'Boots', 'https://www.boots.com/babybjorn-potty-chair-white-grey-10220345', NULL, 'Â£29.99', 'in_stock', '18m+', 'A stable potty chair with a high back and splash guard for practice sitting, with a removable pot that empties easily.', 'Practice sitting comes before dry days. A proper chair helps them stay put long enough to try. Best first potty when they are curious about the toilet and need a steady seat of their own. Keep BabyBjorn Potty Chair in easy reach for the next short try.', 'Practice sitting comes before dry days. A proper chair helps them stay put long enough to try. Best first potty when they are curious about the toilet and need a steady seat of their own. Keep BabyBjorn Potty Chair in easy reach for the next short try.', NULL, 'buy', false, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_potty_chair', 2, 2, 'visible', true, true, 'Best for easy pour potty', 'Pourty Easy Pour Potty', 'Pourty', 'Boots', 'https://www.boots.com/pourty-easy-pour-potty-white-10204787', NULL, 'Â£19.99', 'in_stock', '18m+', 'A lightweight potty with a clever pour spout so emptying into the toilet is cleaner and quicker after practice sits.', 'Emptying without spills keeps parents keener to keep offering sits. The spout is the quiet hero of the design. Strong when you already tried a basic potty and mess was the hard part at home. Leave Pourty Easy Pour Potty out where they can find it again tomorrow.', 'Emptying without spills keeps parents keener to keep offering sits. The spout is the quiet hero of the design. Strong when you already tried a basic potty and mess was the hard part at home. Leave Pourty Easy Pour Potty out where they can find it again tomorrow.', NULL, 'buy', false, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_potty_chair', 3, 3, 'visible', true, true, 'Best for travel potty', 'My Carry Potty Travel Potty Dino', 'My Carry Potty', 'Boots', 'https://www.boots.com/my-carry-potty-dino-10204700', NULL, 'Â£29.99', 'in_stock', '15m+', 'A sealed travel potty with a carry handle and character lid for practice sits away from home without leaks in the bag.', 'Outings are where practice wobbles most. A sealed carry potty keeps the routine going in the car or at grandparents. Best when home sits are going fine and days out are the gap. One short go with My Carry Potty Travel is enough before you tidy away.', 'Outings are where practice wobbles most. A sealed carry potty keeps the routine going in the car or at grandparents. Best when home sits are going fine and days out are the gap. One short go with My Carry Potty Travel is enough before you tidy away.', NULL, 'buy', false, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'check_url'),
    ('cat_potty_chair', 4, 4, 'visible', true, true, 'Best for compact smart potty', 'BabyBjorn Smart Potty', 'BabyBjÃ¶rn', 'Boots', 'https://www.boots.com/babybjorn-smart-potty-white-10220347', NULL, 'Â£24.99', 'in_stock', '18m+', 'A compact potty with a splash guard and easy empty design for smaller bathrooms and upstairs spare seats. for everyday play at home with you.', 'A smaller potty fits tight bathrooms and second seats upstairs. Same trusted brand, different footprint. Useful when the full chair lives downstairs and naps upstairs need a spare. Stay nearby while they try BabyBjorn Smart Potty, then stop on a good note.', 'A smaller potty fits tight bathrooms and second seats upstairs. Same trusted brand, different footprint. Useful when the full chair lives downstairs and naps upstairs need a spare. Stay nearby while they try BabyBjorn Smart Potty, then stop on a good note.', NULL, 'buy', false, NULL, NULL, NULL, 'strong', ARRAY[]::text[], 'none'),
    ('cat_potty_chair', 5, 5, 'visible', true, true, 'Best for toilet seat practice', 'Pourty Potty Training Seat', 'Pourty', 'Boots', 'https://www.boots.com/pourty-potty-training-seat-white-10204788', NULL, '£12.99', 'in_stock', '18m+', 'A child toilet seat that sits on the grown-up loo for practice sits when they are curious about the big toilet, not only a floor potty.', 'Near two, some children skip straight to the big toilet. A seat reduces wobble without buying a second floor potty. Good when the chair is already covered and they want the real loo. Put Pourty Potty Training Seat where you both sit most evenings so the invite is easy.', 'Near two, some children skip straight to the big toilet. A seat reduces wobble without buying a second floor potty. Good when the chair is already covered and they want the real loo. Put Pourty Potty Training Seat where you both sit most evenings so the invite is easy.', NULL, 'buy', false, NULL, NULL, NULL, 'good', ARRAY[]::text[], 'none')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
